const AWS = require('aws-sdk');
const { execFile } = require('child_process');
const s3 = new AWS.S3();

exports.handler = async (event) => {
  const bucketName = process.env.BUCKET_NAME;
  const allowedFormats = ['jpg', 'png', 'gif'];

  for (const record of event.Records) {
    const key = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
    const outputFormat = record.s3.object.metadata.outputFormat;

    if (!allowedFormats.includes(outputFormat)) {
      console.error(`Unsupported format: ${outputFormat}`);
      return;
    }

    const inputFilePath = `/tmp/${key}`;
    const outputFilePath = `/tmp/output.${outputFormat}`;

    try {
      await s3.getObject({ Bucket: bucketName, Key: key }).promise()
        .then(data => require('fs').promises.writeFile(inputFilePath, data.Body));

      await new Promise((resolve, reject) => {
        execFile('convert', [inputFilePath, outputFilePath], (error) => {
          if (error) reject(error);
          else resolve();
        });
      });

      const outputData = await require('fs').promises.readFile(outputFilePath);

      await s3.putObject({
        Bucket: bucketName,
        Key: `converted/${key}.${outputFormat}`,
        Body: outputData,
        ContentType: `image/${outputFormat}`
      }).promise();

    } catch (error) {
      console.error(`Error processing file ${key}:`, error);
    } finally {
      require('fs').promises.unlink(inputFilePath).catch(() => {});
      require('fs').promises.unlink(outputFilePath).catch(() => {});
    }
  }
};